//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Header/footer references and type matching (default/even/first)".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from
//! ECMA-376 / ISO 29500-1 / MS-OI29500 about how `headerReference` /
//! `footerReference` (EG_HdrFtrReferences, CT_HdrFtrRef) must be serialized,
//! synthesized, ordered, and type-matched inside `CT_SectPr`.
//!
//! A FAILING assertion here encodes a REAL Word-compliance gap in the stemma
//! engine. Do NOT weaken an assertion to make it pass: a fail is the finding
//! we are hunting. Each assert message carries the rule text + §refs so a
//! failure is self-explanatory.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim, so `reserialize()` of an unedited document reflects
//! stemma's verbatim-preservation contract, not Word's render normalization.
//! The xml* assertions below therefore target only markup the serializer
//! ACTIVELY generates or restructures — CT_SectPr child ORDERING (Annex A
//! sequence), reference SYNTHESIS, exact ST_HdrFtr enum spelling, and
//! opens-clean validity — never "Word ignores value V on layout".

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;
use zip::write::FileOptions;

// ─── Prelude: minimal-docx plumbing ──────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body> … </w:body></w:document>` (it MUST already include a
/// trailing `<w:sectPr>` if the test wants one). `extra_parts` are additional
/// parts written verbatim under `word/` (e.g. `("styles.xml", "<…/>")`); a
/// content-type override is emitted for each based on its file stem.
///
/// Every `<w:headerReference>`/`<w:footerReference>` `r:id` the body uses gets
/// a real relationship and a minimal valid header/footer part, so the fixture
/// is a *valid* package (a dangling reference is a repair/data-loss class the
/// serialize gate refuses to emit).
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    // (rid, is_header) for each header/footer reference in the body.
    let mut hdrftr_rids: Vec<(String, bool)> = Vec::new();
    for (marker, is_header) in [("<w:headerReference", true), ("<w:footerReference", false)] {
        for frag in body_xml.split(marker).skip(1) {
            let frag = frag.split("/>").next().unwrap_or(frag);
            if let Some(pos) = frag.find("r:id=\"") {
                let rest = &frag[pos + 6..];
                if let Some(end) = rest.find('\"') {
                    hdrftr_rids.push((rest[..end].to_string(), is_header));
                }
            }
        }
    }
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for each extra part, keyed off the file stem.
    let mut overrides = String::new();
    for (name, _) in extra_parts {
        let ct = match *name {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            "header1.xml" | "header2.xml" | "header3.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.header+xml"
            }
            "footer1.xml" | "footer2.xml" | "footer3.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.footer+xml"
            }
            other => panic!("make_docx: unknown extra part content-type for {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{name}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // One relationship + one minimal valid part per header/footer reference.
    let mut hdrftr_rel_entries = String::new();
    let mut hdrftr_parts: Vec<(String, String)> = Vec::new();
    let mut hdrftr_overrides = String::new();
    for (i, (rid, is_header)) in hdrftr_rids.iter().enumerate() {
        let (kind, rel_type, root_el, ct) = if *is_header {
            (
                "header",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/header",
                "hdr",
                "application/vnd.openxmlformats-officedocument.wordprocessingml.header+xml",
            )
        } else {
            (
                "footer",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/footer",
                "ftr",
                "application/vnd.openxmlformats-officedocument.wordprocessingml.footer+xml",
            )
        };
        // Numbered from 7 to avoid colliding with extra_parts header1-3/footer1-3.
        let part = format!("{kind}{}.xml", i + 7);
        hdrftr_rel_entries.push_str(&format!(
            r#"<Relationship Id="{rid}" Type="{rel_type}" Target="{part}"/>"#
        ));
        hdrftr_overrides.push_str(&format!(
            r#"<Override PartName="/word/{part}" ContentType="{ct}"/>"#
        ));
        hdrftr_parts.push((part, format!(
            r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:{root_el} xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:p><w:r><w:t>story</w:t></w:r></w:p></w:{root_el}>"#
        )));
    }
    let content_types = content_types.replace("</Types>", &format!("{hdrftr_overrides}</Types>"));
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{hdrftr_rel_entries}</Relationships>"#
    );

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, content) in extra_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        for (name, content) in &hdrftr_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse -> serialize (default options) -> the re-emitted `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

// ─── Ordering helpers (regex-free; `regex` crate is not a dep) ────────────────
//
// The TestSpec `xmlRegex` expectations are all positional/ordering or
// occurrence-count assertions over the serialized XML. We translate each into
// explicit byte-offset / substring-count checks so the behavioural claim is
// preserved exactly without pulling in a regex engine.

/// Index of the first `<TAG` start whose tag text (up to the closing `>`)
/// contains `attr`. Used to find e.g. a `<w:headerReference … w:type="first" …>`.
fn first_element_with_attr(xml: &str, tag: &str, attr: &str) -> Option<usize> {
    let open = format!("<{tag}");
    let mut search = 0usize;
    while let Some(rel) = xml[search..].find(&open) {
        let start = search + rel;
        let gt = xml[start..].find('>').map(|g| start + g)?;
        if xml[start..=gt].contains(attr) {
            return Some(start);
        }
        search = gt + 1;
    }
    None
}

/// Index of the first start tag `<TAG` (any attrs).
fn first_tag(xml: &str, tag: &str) -> Option<usize> {
    xml.find(&format!("<{tag}"))
}

/// Count of start tags `<TAG`.
fn count_tag(xml: &str, tag: &str) -> usize {
    xml.matches(&format!("<{tag}")).count()
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[test]
fn hdrftr_refs_serialized_at_sectpr_head_in_authored_order() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="default" r:id="rIdH"/><w:footerReference w:type="default" r:id="rIdF"/><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // (a) authored header(default) precedes footer(default): EG_HdrFtrReferences
    //     is a repeatable choice with no header-vs-footer ordering constraint, so
    //     the authored order must be preserved on reserialize.
    let h = first_element_with_attr(&xml, "w:headerReference", r#"w:type="default""#);
    let f = first_element_with_attr(&xml, "w:footerReference", r#"w:type="default""#);
    assert!(
        h.is_some() && f.is_some() && h < f,
        "EG_HdrFtrReferences is a repeatable choice with no header-vs-footer order constraint; authored header(default) must precede footer(default) on reserialize (ECMA-376 Annex A CT_SectPr / EG_HdrFtrReferences; ISO 29500-1 §17.10.5, §17.10.2). header={h:?} footer={f:?}\nXML: {xml}"
    );

    // (b) all hdr/ftr refs precede pgSz: EG_HdrFtrReferences is the leading group
    //     of CT_SectPr, before EG_SectPrContents (pgSz).
    let pg = first_tag(&xml, "w:pgSz");
    assert!(
        h.is_some() && f.is_some() && pg.is_some() && h < pg && f < pg,
        "Annex A: EG_HdrFtrReferences is the leading group of CT_SectPr, so all header/footer refs must serialize before pgSz (ISO 29500-1 §17.10.5, §17.10.2). header={h:?} footer={f:?} pgSz={pg:?}\nXML: {xml}"
    );
}

#[test]
fn titlepg_section_without_refs_synthesizes_nothing_and_opens_clean() {
    // FINDING (was the premise of a synthesis test-bug): stemma does NOT
    // synthesize blank header/footer references for a first section that carries
    // titlePg but no refs — it re-zips `<w:sectPr><w:titlePg/></w:sectPr>`
    // verbatim. Word does not require synthesized refs either: the §17.10.5/
    // §17.10.6 "blank/inherited first-page header" rule is a consumption/layout
    // behaviour, not a stored-markup requirement, and the package opens clean
    // without any synthesized reference. So the correct contract is: no
    // synthesis, verbatim round-trip, opens clean.
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:titlePg/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        first_tag(&xml, "w:headerReference").is_none()
            && first_tag(&xml, "w:footerReference").is_none(),
        "stemma must not fabricate header/footer references for a titlePg section that has none; the sectPr round-trips verbatim (ISO 29500-1 §17.10.5, §17.10.2 are consumption rules, not save-synthesis).\nXML: {xml}"
    );
    assert!(
        xml.contains("<w:titlePg"),
        "the authored titlePg must survive the round-trip.\nXML: {xml}"
    );

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "a titlePg section with no header/footer references is conformant and opens without repair (no dangling reference is introduced). issues={:?}",
        report.issues
    );
}

#[test]
fn plain_section_without_refs_synthesizes_no_header_ref_and_opens_clean() {
    // FINDING (was a synthesis test-bug premise): stemma does NOT synthesize a
    // default headerReference for a section that has none — it re-zips
    // `<w:sectPr><w:pgSz/></w:sectPr>` verbatim. The "odd/default header is used"
    // rule (MS-OI §2.1.298 / §17.10.5) is a consumption/layout behaviour: Word
    // resolves the displayed header at render, it does not write a synthesized
    // reference into the stored markup. The section opens clean as-is.
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        first_tag(&xml, "w:headerReference").is_none(),
        "stemma must not fabricate a default headerReference for a section that has none; header resolution is a consumption rule (MS-OI §2.1.298 / §17.10.5), not save-synthesis.\nXML: {xml}"
    );
    assert!(
        !xml.contains(r#"w:type="first""#),
        "with no titlePg, no First reference may be synthesized either.\nXML: {xml}"
    );

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "a section with no header reference is conformant and opens without repair. issues={:?}",
        report.issues
    );
}

#[test]
fn empty_sectpr_synthesizes_no_refs_and_opens_clean() {
    // FINDING (was a synthesis test-bug premise): an empty `<w:sectPr/>`
    // round-trips verbatim with NO synthesized header/footer references. Word does
    // not require them — header/footer resolution is a consumption rule, and the
    // empty section opens clean as-is.
    let body = r#"<w:p><w:r><w:t>Only section</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        first_tag(&xml, "w:headerReference").is_none()
            && first_tag(&xml, "w:footerReference").is_none(),
        "stemma must not fabricate header/footer references for an empty sectPr; resolution is a consumption rule (MS-OI §2.1.298/§2.1.295), not save-synthesis.\nXML: {xml}"
    );
    assert!(
        !xml.contains(r#"w:type="first""#),
        "no First reference of either kind may be synthesized without titlePg.\nXML: {xml}"
    );

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "an empty sectPr is conformant and opens without repair. issues={:?}",
        report.issues
    );
}

#[test]
fn hdrftr_type_attr_roundtrips_exact_enum_spelling() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="first" r:id="rH1"/><w:headerReference w:type="even" r:id="rH2"/><w:headerReference w:type="default" r:id="rH3"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains(r#"w:type="first""#),
        "A first-kind header reference must re-serialize its type as the literal ST_HdrFtr token 'first' (ISO 29500-1 §17.18.36; ECMA-376 Part 4 §2.18.41 ST_HdrFtr).\nXML: {xml}"
    );
    assert!(
        xml.contains(r#"w:type="even""#),
        "An even-kind header reference must re-serialize its type as the literal ST_HdrFtr token 'even' (ISO 29500-1 §17.18.36).\nXML: {xml}"
    );
    assert!(
        xml.contains(r#"w:type="default""#),
        "A default-kind header reference must re-serialize its type as the literal ST_HdrFtr token 'default' (ISO 29500-1 §17.18.36).\nXML: {xml}"
    );
}

#[test]
fn six_hdrftr_refs_all_types_preserved() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="default" r:id="rH1"/><w:headerReference w:type="first" r:id="rH2"/><w:headerReference w:type="even" r:id="rH3"/><w:footerReference w:type="default" r:id="rF1"/><w:footerReference w:type="first" r:id="rF2"/><w:footerReference w:type="even" r:id="rF3"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    let headers = count_tag(&xml, "w:headerReference");
    let footers = count_tag(&xml, "w:footerReference");
    assert!(
        headers >= 3,
        "All three header references (default/first/even) must survive the round-trip; CT_SectPr permits up to 6 refs (ISO 29500-1 §17.10.5; ECMA-376 Annex A CT_SectPr). found {headers} headerReference\nXML: {xml}"
    );
    assert!(
        footers >= 3,
        "All three footer references (default/first/even) must survive the round-trip; CT_SectPr permits up to 6 refs (ISO 29500-1 §17.10.2; ECMA-376 Annex A CT_SectPr). found {footers} footerReference\nXML: {xml}"
    );
}

/// ORACLE-RESOLVED (Word `/validate`): a headerReference with
/// `w:type="odd"` (outside the closed ST_HdrFtr {default,even,first}) opens
/// WITHOUT repair (`repaired=false`). Word tolerates the out-of-enum value, so
/// stemma's silent import coercion (odd → Default) is acceptable and the package
/// must validate clean. ISO 29500-1 §17.10.5; ECMA-376 Annex A ST_HdrFtr.
#[test]
fn hdrftr_ref_invalid_type_value_opens_clean() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="odd" r:id="rId99"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "real Word opens a headerReference with type=\"odd\" without repair (oracle /validate: repaired=false); the out-of-enum type is tolerated, so stemma's coercion to Default is acceptable and the package validates clean. issues={:?}",
        report.issues
    );
}

/// ORACLE-RESOLVED (Word `/validate`): a headerReference MISSING its
/// `w:type` attribute opens WITHOUT repair (`repaired=false`). Word tolerates the
/// absent type (CT_HdrFtrRef's `type use="required"` is not repair-enforced), so
/// stemma's silent default-kind assignment is acceptable and the package must
/// validate clean. ECMA-376 Annex A CT_HdrFtrRef; ISO 29500-1 §17.10.5.
#[test]
fn hdrftr_ref_missing_type_attribute_opens_clean() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference r:id="rId99"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "real Word opens a headerReference with no w:type without repair (oracle /validate: repaired=false); the required-by-schema type is not repair-enforced, so stemma's default-kind assignment is acceptable and the package validates clean. issues={:?}",
        report.issues
    );
}

/// I-REL-004: a `w:headerReference` that OMITS its required `r:id` is
/// non-conformant — the header relationship cannot be resolved, so Word reports
/// needs-repair and `validate()` must report an error.
/// ISO 29500-1 §17.10.5; ECMA-376 Annex A CT_HdrFtrRef / CT_Rel; OPC §6.5.
#[test]
fn header_reference_missing_rid_is_nonconformant() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="default"/><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        !report.ok,
        "r:id is required on CT_HdrFtrRef (which extends CT_Rel, r:id use=\"required\"); a headerReference that omits it names no relationship and cannot be resolved, so the package is non-conformant and Word reports needs-repair. validate() must report an error (I-REL-004). issues={:?}",
        report.issues
    );
}

/// I-REL-004: the footer reference is the same CT_HdrFtrRef shape, so an omitted
/// `r:id` on `w:footerReference` is likewise non-conformant.
#[test]
fn footer_reference_missing_rid_is_nonconformant() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:footerReference w:type="default"/><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        !report.ok,
        "r:id is required on CT_HdrFtrRef; a footerReference that omits it names no relationship, so the package is non-conformant. validate() must report an error (I-REL-004). issues={:?}",
        report.issues
    );
}

/// I-REL-004: an EMPTY `r:id=""` on a header reference is non-conformant too.
/// ORACLE-CONFIRMED (Word `/validate`): a headerReference with
/// `r:id=""` opens WITH REPAIR (`repaired=true`) — Word treats the empty
/// required reference as a defect, not a tolerated placeholder. This is the
/// OPPOSITE of empty `r:embed`/`r:link` on `a:blip` (a conformant empty
/// placeholder, see `empty_rembed_rlink_not_dangling`): `r:id` is *required* on
/// CT_HdrFtrRef. The earlier "empty is schema-valid, opens clean" hypothesis was
/// overturned by the oracle. ISO 29500-1 §17.10.5; ECMA-376 Annex A CT_HdrFtrRef.
#[test]
fn header_reference_empty_rid_is_nonconformant() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="default" r:id=""/><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let report = stemma::api::validate(&b);
    assert!(
        !report.ok,
        "an empty r:id=\"\" names no relationship; r:id is required on CT_HdrFtrRef, and real Word opens this only with repair (oracle /validate: repaired=true), so it is non-conformant and validate() must report an error (I-REL-004). issues={:?}",
        report.issues
    );
}
